module top_module(
	output word,
	input [3:0] row, col,
	input [1:0] select
);reg [15:0] pattern_matrix[15:0];

integer i;
always @(*)
begin
	if (select == 1) begin
		pattern_matrix[0] = 16'b0000000000000000;
		pattern_matrix[1] = 16'b0000000000000000;
		pattern_matrix[2] = 16'b0000111111110000;
		pattern_matrix[3] = 16'b0001111111111000;
		pattern_matrix[4] = 16'b0011100000011100;
		pattern_matrix[5] = 16'b0111000000001110;
		pattern_matrix[6] = 16'b0111000000001110;
		pattern_matrix[7] = 16'b0111000000001110;
		pattern_matrix[8] = 16'b0111000000001110;
		pattern_matrix[9] = 16'b0111000000001110;
		pattern_matrix[10] =16'b0111000000001110;
		pattern_matrix[11] =16'b0111000000001110;
		pattern_matrix[12] =16'b0111000000001110;
		pattern_matrix[13] =16'b0011111111111100;
		pattern_matrix[14] =16'b0001111111111000;
		pattern_matrix[15] =16'b0000000000000000;
	end else if (select == 2) begin
		pattern_matrix[0] = 16'b0000000000000000;
		pattern_matrix[1] = 16'b1110000000000111;
		pattern_matrix[2] = 16'b0111000000001110;
		pattern_matrix[3] = 16'b0011100000011100;
		pattern_matrix[4] = 16'b0001110000111000;
		pattern_matrix[5] = 16'b0000111001110000;
		pattern_matrix[6] = 16'b0000011111100000;
		pattern_matrix[7] = 16'b0000001111000000;
		pattern_matrix[8] = 16'b0000001111000000;
		pattern_matrix[9] = 16'b0000011111100000;
		pattern_matrix[10] =16'b0000111001110000;
		pattern_matrix[11] =16'b0001110000111000;
		pattern_matrix[12] =16'b0011100000011100;
		pattern_matrix[13] =16'b0111000000001110;
		pattern_matrix[14] =16'b1110000000000111;
		pattern_matrix[15] =16'b0000000000000000;
	end else for (i=0; i<16; i=i+1)
		pattern_matrix[i] = 16'b0;
end

assign word = (select == 0) ? 1'b0 : (pattern_matrix[row] >> (~col)) % 2;

endmodule
